SELECT count(*) FROM kind_type, title, cast_info, name, aka_name, char_name, movie_keyword, role_type, keyword WHERE title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.person_role_id = char_name.id AND movie_keyword.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_keyword.keyword_id = keyword.id;